import { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import api from "../../api/axios";

export default function EditMyAppointment() {
  const { id } = useParams();
  const navigate = useNavigate();

  const [date, setDate] = useState("");
  const [time, setTime] = useState("");
  const [availableSlots, setAvailableSlots] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [minDate, setMinDate] = useState("");

  // Get tomorrow's date as minimum (future dates only)
  useEffect(() => {
    const tomorrow = new Date();
    tomorrow.setDate(tomorrow.getDate() + 1);
    const minDateStr = tomorrow.toISOString().split("T")[0];
    setMinDate(minDateStr);
  }, []);

  useEffect(() => {
    api.get(`/customer/appointments/my`)
      .then((res) => {
        const found = res.data.find((a) => a._id === id);
        if (!found) {
          alert("Appointment not found");
          navigate("/my-appointments");
          return;
        }
        setDate(String(found.date).slice(0, 10));
        setTime(found.time);
      })
      .catch((err) => alert(err.response?.data?.message || "Failed to load"));
  }, [id, navigate]);

  // Load available time slots when date changes
  useEffect(() => {
    const loadTimeSlots = async () => {
      if (!date) {
        setAvailableSlots([]);
        setTime("");
        return;
      }

      setLoading(true);
      setError("");

      try {
        const res = await api.get(`/customer/appointments/available-slots/${date}?excludeAppointmentId=${id}`);
        const slots = res.data.slots || [];

        if (slots.length === 0) {
          setError("No available slots on this date. Please select another date.");
          setAvailableSlots([]);
        } else {
          setAvailableSlots(slots);
        }
      } catch (err) {
        const errorMsg = err.response?.data?.message || err.response?.data?.errors?.[0] || "Failed to load available slots";
        setError(errorMsg);
        setAvailableSlots([]);
      } finally {
        setLoading(false);
      }
    };

    loadTimeSlots();
  }, [date]);

  const submit = async (e) => {
    e.preventDefault();

    if (!date) {
      alert("Please select a date");
      return;
    }

    if (!time) {
      alert("Please select a time");
      return;
    }

    try {
      await api.put(`/customer/appointments/${id}`, { date, time });
      alert("Appointment updated successfully!");
      navigate("/my-appointments");
    } catch (err) {
      alert(err.response?.data?.message || "Update failed");
    }
  };

  return (
    <div className="page">
      <div className="pageHead">
        <div>
          <div className="pageTitle">Edit My Appointment</div>
          <div className="pageSub">Update your appointment date and time (9:00 AM - 5:00 PM, 1-hour sessions)</div>
        </div>
      </div>

      <div className="card cardPad" style={{ maxWidth: 560, margin: "32px auto" }}>
        <form onSubmit={submit}>
          <label className="label">Date</label>
          <input 
            type="date" 
            value={date} 
            onChange={(e) => setDate(e.target.value)} 
            required 
            min={minDate}
            className="input" 
          />
          <p style={{ fontSize: 12, color: "#666", marginTop: 4 }}>Select a future date (shop closed on holidays)</p>

          {error && (
            <div style={{ 
              marginTop: 12, 
              padding: 12, 
              backgroundColor: "#fee", 
              color: "#c33",
              borderRadius: 4,
              fontSize: 14
            }}>
              {error}
            </div>
          )}

          {date && !error && (
            <>
              <label className="label" style={{ marginTop: 20 }}>Select Time Slot</label>
              {loading ? (
                <div style={{ padding: 12, textAlign: "center", color: "#666" }}>Loading available times...</div>
              ) : availableSlots.length > 0 ? (
                <div style={{ 
                  display: "grid", 
                  gridTemplateColumns: "repeat(auto-fill, minmax(100px, 1fr))",
                  gap: 8,
                  marginTop: 8
                }}>
                  {availableSlots.map((slot) => (
                    <button
                      key={slot.time}
                      type="button"
                      onClick={() => setTime(slot.time)}
                      className="btn"
                      style={{
                        backgroundColor: time === slot.time ? "#007bff" : "#f0f0f0",
                        color: time === slot.time ? "white" : "#333",
                        border: time === slot.time ? "2px solid #0056b3" : "1px solid #ddd",
                        padding: 10,
                        cursor: slot.availableStaffCount > 0 ? "pointer" : "not-allowed",
                        opacity: slot.availableStaffCount > 0 ? 1 : 0.5,
                        fontSize: 14
                      }}
                      disabled={slot.availableStaffCount === 0}
                      title={`${slot.availableStaffCount} staff member${slot.availableStaffCount !== 1 ? 's' : ''} available`}
                    >
                      {slot.time}
                      <br />
                      <small>({slot.availableStaffCount} available)</small>
                    </button>
                  ))}
                </div>
              ) : null}
            </>
          )}

          <div style={{ marginTop: 28, display: "flex", gap: 12 }}>
            <button type="submit" disabled={!date || !time} className="btn btnPrimary">Update</button>
            <button type="button" onClick={() => navigate("/my-appointments")} className="btn">Cancel</button>
          </div>
        </form>
      </div>
    </div>
  );
}
